/* `kind`:
 *  - 'studio'   → axlab itself, the umbrella. Always rendered as the
 *                  bento's featured cell.
 *  - 'lab'      → built for / shipped under axlab. Gets the `{x}lab` badge.
 *  - 'personal' → built for fun / learning / curiosity. Gets the "personal" tag.
 *  - 'wip'      → not shipped yet. Gets a "Building" pill.
 */
export type ProjectKind = 'studio' | 'lab' | 'personal' | 'wip';

