// Stack bento items — 12-column × 5-row explicit grid (square units via ResizeObserver)
// type: 'wiki-img' = single-color logo, 'wiki-gray' = multi-color logo, 'lobehub' = Mono icon, 'text' = label only
// bg: cell background from teal palette (#032f2b · #075e55 · #0a8d80 · #0dbcaa)
// iconDark: true → use dark (#0b0f14) icons (for lighter cells)
export type StackItem = {
  label: string;
  type: 'wiki-img' | 'wiki-gray' | 'lobehub' | 'text';
  src?: string;
  lobeName?: string;
  gridCol: string;
  gridRow: string;
  mobileGridCol?: string;
  mobileGridRow?: string;
  showLabel?: boolean;
  bg?: string;
  isHero?: boolean;
  iconDark?: boolean;
  noFilter?: boolean;   // true → render img as-is (pre-colored SVG)
  iconScale?: number;   // multiplier applied to computed iconSize (default 1.0)
  info?: string;        // shown in click/hover popup
  mobileHidden?: boolean; // true → not rendered on mobile
};

